import React from 'react';
import '../../variables.css';
import '../../index.css';
import './About.css';

import imgTime from '../../assets/img/aboutimg/rafael.png';
import imgGuilherme from '../../assets/img/aboutimg/lucas.png';
import imgGiovanna from '../../assets/img/aboutimg/giovanna.png';


function About() {
    return (
        <div className="about-container">
            {/* Seção Hero */}
            <section className="hero-section">
                <h1>Sobre a ConectEdu</h1>
                <p>Conectando escolas através da tecnologia</p>
            </section>

            {/* Seção Missão, Visão e Valores */}
            <section className="mission-section">
                <div className="mission-card">
                    <h2>Nossa Missão</h2>
                    <p>Democratizar o acesso à tecnologia na educação, conectando escolas e doadores.</p>
                </div>

                <div className="mission-card">
                    <h2>Nossa Visão</h2>
                    <p>Um futuro onde todas as escolas tenham acesso igualitário à tecnologia.</p>
                </div>

                <div className="mission-card">
                    <h2>Nossos Valores</h2>
                    <ul>
                        <li>Educação para todos</li>
                        <li>Inovação</li>
                        <li>Sustentabilidade</li>
                        <li>Transparência</li>
                    </ul>
                </div>
            </section>

            {/* Seção Sobre */}
            <section className="about-section">
                <h2>Quem Somos</h2>
                <p>A ConectEdu é uma plataforma que visa facilitar a doação de equipamentos tecnológicos para escolas, 
                   criando uma ponte entre doadores e instituições de ensino.</p>
            </section>
        </div>
    );
}

export default About;
